      for (let i = 0; i < 5; i++) {
        expect(limiter.allow("k", 0)).toBe(true);
      }
      expect(limiter.allow("k", 0)).toBe(false);
      // Just before the whole window elapses, still blocked.
      expect(limiter.allow("k", 59999)).toBe(false);
      // At exactly 60000 later, the original calls (t=0) have expired
      // (0 > 60000 - 60000 === 0 is false), so a call is allowed again.
      expect(limiter.allow("k", 60000)).toBe(true);
